```class Solution {
    public long maximumOr(int[] nums, int k) {
        long res = 0;
        for (int num : nums) {
            res |= num;
        }
        for (int i = 0; i < k; i++) {
            int maxIndex = -1;
            int maxVal = 0;
            for (int j = 0; j < nums.length; j++) {
                if (nums[j] > maxVal) {
                    maxVal = nums[j];
                    maxIndex = j;
                }
            }
            res |= maxVal << 1;
            nums[maxIndex] = maxVal << 1;
        }
        return res;
    }
}```
